import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  forwardRef,
  InjectionToken,
  input,
  model,
  output,
  signal,
  ViewEncapsulation,
} from '@angular/core';
import { BrnCollapsible } from '@spartan-ng/brain/collapsible';
import { cn } from '@gremorie/ng-core';

/**
 * Reasoning — collapsible "thinking..." block. Mirrors React `Reasoning`.
 *
 * Behavior parity:
 * - Auto-opens when streaming starts (if `defaultOpen`).
 * - Auto-closes 1s after streaming ends (once only).
 * - Tracks duration in seconds from streaming start to end.
 * - `[(open)]` two-way binding (model signal) plus uncontrolled
 *   `defaultOpen`.
 *
 * Anti-pattern note (from rx-ai source): React useEffect deps array caused
 * "Maximum update depth exceeded" because useControllableState returned
 * fresh setters every render. Angular signals don't have that problem
 * because effect() tracks signal reads, not the identity of the setter.
 */
export interface ReasoningState {
  isStreaming: () => boolean;
  isOpen: () => boolean;
  duration: () => number | undefined;
}

export const REASONING = new InjectionToken<ReasoningState>('ReasoningState');

const AUTO_CLOSE_DELAY = 1000;
const MS_IN_S = 1000;

@Component({
  selector: 'reasoning',
  standalone: true,
  imports: [BrnCollapsible],
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div brnCollapsible [(expanded)]="open">
      <ng-content />
    </div>
  `,
  host: {
    '[class]': 'hostClass()',
  },
  providers: [{ provide: REASONING, useExisting: forwardRef(() => Reasoning) }],
})
export class Reasoning implements ReasoningState {
  readonly isStreaming = input<boolean>(false);
  readonly defaultOpen = input<boolean>(true);
  readonly open = model<boolean>(true);
  // Aliased to `duration` on purpose: the public `duration()` method below
  // (required by ReasoningState) merges this binding with the auto-tracked
  // value, so the raw input takes the internal `durationInput` name.
  /* eslint-disable @angular-eslint/no-input-rename */
  readonly durationInput = input<number | undefined>(undefined, {
    alias: 'duration',
  });
  /* eslint-enable @angular-eslint/no-input-rename */

  readonly openChange = output<boolean>();

  private readonly _duration = signal<number | undefined>(undefined);
  private readonly _hasAutoClosed = signal(false);
  private readonly _startTime = signal<number | null>(null);
  private autoCloseTimer?: ReturnType<typeof setTimeout>;

  readonly duration = () => this.durationInput() ?? this._duration();
  readonly isOpen = () => this.open();

  protected readonly hostClass = computed(() => cn('not-prose mb-4 block'));

  constructor() {
    // Apply defaultOpen on init.
    effect(() => {
      this.open.set(this.defaultOpen());
    });

    // Emit openChange when open flips.
    effect(() => {
      this.openChange.emit(this.open());
    });

    // Track duration from streaming start to end.
    effect(() => {
      const streaming = this.isStreaming();
      if (streaming) {
        if (this._startTime() === null) {
          this._startTime.set(Date.now());
        }
      } else {
        const start = this._startTime();
        if (start !== null) {
          this._duration.set(Math.ceil((Date.now() - start) / MS_IN_S));
          this._startTime.set(null);
        }
      }
    });

    // Auto-close when streaming ends (once only).
    effect((onCleanup) => {
      const streaming = this.isStreaming();
      const open = this.open();
      const defaultO = this.defaultOpen();
      const auto = this._hasAutoClosed();
      if (defaultO && !streaming && open && !auto) {
        this.autoCloseTimer = setTimeout(() => {
          this.open.set(false);
          this._hasAutoClosed.set(true);
        }, AUTO_CLOSE_DELAY);
        onCleanup(() => {
          if (this.autoCloseTimer) clearTimeout(this.autoCloseTimer);
        });
      }
    });
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';
import { BrnCollapsibleTrigger } from '@spartan-ng/brain/collapsible';

import { Shimmer } from '../shimmer/shimmer';
import { REASONING } from './reasoning';

/**
 * ReasoningTrigger — clickable header for the Reasoning collapsible.
 *
 * Default text follows React `defaultGetThinkingMessage`:
 * - "Thinking…" (shimmered) while streaming or duration is 0
 * - "Thought for a few seconds" when duration is undefined
 * - "Thought for {duration} seconds" otherwise
 *
 * Project custom children to fully override.
 */
@Component({
  selector: 'reasoning-trigger',
  standalone: true,
  imports: [BrnCollapsibleTrigger, Shimmer],
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <button
      type="button"
      brnCollapsibleTrigger
      class="flex w-full items-center gap-2 text-muted-foreground text-sm transition-colors hover:text-foreground"
    >
      <ng-content>
        <!-- brain icon -->
        <svg
          width="16"
          height="16"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          stroke-linecap="round"
          stroke-linejoin="round"
          aria-hidden="true"
        >
          <path
            d="M12 5a3 3 0 1 0-5.997.125 4 4 0 0 0-2.526 5.77 4 4 0 0 0 .556 6.588A4 4 0 1 0 12 18Z"
          />
          <path
            d="M12 5a3 3 0 1 1 5.997.125 4 4 0 0 1 2.526 5.77 4 4 0 0 1-.556 6.588A4 4 0 1 1 12 18Z"
          />
          <path d="M15 13a4.5 4.5 0 0 1-3-4 4.5 4.5 0 0 1-3 4" />
          <path d="M17.599 6.5a3 3 0 0 0 .399-1.375" />
          <path d="M6.003 5.125A3 3 0 0 0 6.401 6.5" />
        </svg>
        @if (showShimmer()) {
          <span ngShimmer [shimmerDuration]="1">Thinking…</span>
        } @else {
          <p>{{ label() }}</p>
        }
        <svg
          width="16"
          height="16"
          viewBox="0 0 24 24"
          fill="none"
          stroke="currentColor"
          stroke-width="2"
          stroke-linecap="round"
          stroke-linejoin="round"
          aria-hidden="true"
          class="transition-transform"
          [class.rotate-180]="open()"
        >
          <path d="m6 9 6 6 6-6" />
        </svg>
      </ng-content>
    </button>
  `,
})
export class ReasoningTrigger {
  private readonly state = inject(REASONING);

  protected readonly open = computed(() => this.state.isOpen());
  protected readonly showShimmer = computed(() => {
    const d = this.state.duration();
    return this.state.isStreaming() || d === 0;
  });

  protected readonly label = computed(() => {
    const d = this.state.duration();
    if (d === undefined) return 'Thought for a few seconds';
    return `Thought for ${d} seconds`;
  });
}

import {
  ChangeDetectionStrategy,
  Component,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { BrnCollapsibleContent } from '@spartan-ng/brain/collapsible';

/**
 * ReasoningContent — collapsible body that holds the reasoning text.
 *
 * React `ReasoningContent` wraps Streamdown; without that Angular peer this
 * component accepts a plain-text `text` input rendered as preserved
 * whitespace, or any projected children for custom renderers.
 */
@Component({
  selector: 'reasoning-content',
  standalone: true,
  imports: [BrnCollapsibleContent],
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div
      brnCollapsibleContent
      class="mt-4 text-sm text-muted-foreground outline-none transition-all data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:animate-in data-[state=open]:slide-in-from-top-2"
    >
      @if (text(); as t) {
        <p class="whitespace-pre-wrap">{{ t }}</p>
      } @else {
        <ng-content />
      }
    </div>
  `,
})
export class ReasoningContent {
  readonly text = input<string>();
}

export { Reasoning, REASONING } from './reasoning';
export type { ReasoningState } from './reasoning';
export { ReasoningTrigger } from './reasoning-trigger';
export { ReasoningContent } from './reasoning-content';
